     1→// app/(tabs)/index.tsx
     2→// Visual Novel Style Home Screen - With Settings Gear Icon
     3→
     4→import { Ionicons } from '@expo/vector-icons';
     5→import { LinearGradient } from 'expo-linear-gradient';
     6→import { useRouter } from 'expo-router';
     7→import { collection, deleteDoc, doc, getDocs, limit, onSnapshot, query, updateDoc, where } from 'firebase/firestore';
     8→import React, { useCallback, useEffect, useRef, useState } from 'react';
     9→import {
    10→  Animated,
    11→  Dimensions,
    12→  Pressable,
    13→  RefreshControl,
    14→  StatusBar,
    15→  StyleSheet,
    16→  Text,
    17→  View,
    18→} from 'react-native';
    19→import { useSafeAreaInsets } from 'react-native-safe-area-context';
