    24→
    25→const { width: SCREEN_WIDTH, height: SCREEN_HEIGHT } = Dimensions.get('window');
    26→const CHARACTER_HEIGHT = 370; // BIGGER - takes up more screen
    27→
    28→// ============== HELPERS ==============
    29→
    30→function getLocalDateString(date: Date = new Date()): string {
    31→  const year = date.getFullYear();
    32→  const month = String(date.getMonth() + 1).padStart(2, '0');
    33→  const day = String(date.getDate()).padStart(2, '0');
    34→  return `${year}-${month}-${day}`;
    35→}
    36→
    37→function getYesterdayDateString(): string {
    38→  const yesterday = new Date();
    39→  yesterday.setDate(yesterday.getDate() - 1);
    40→  return getLocalDateString(yesterday);
    41→}
    42→
    43→function getTimeBasedGreeting(): string {
    44→  const hour = new Date().getHours();
    45→  if (hour >= 5 && hour < 12) return 'Morning';
    46→  if (hour >= 12 && hour < 17) return 'Afternoon';
    47→  if (hour >= 17 && hour < 22) return 'Evening';
    48→  return 'Late night';
    49→}
    50→
    51→function getMotivationalMessage(completed: number, total: number): string {
    52→  if (total === 0) return "Oi, you haven't set up any habits yet! Let's get you sorted, yeah?";
    53→  
    54→  const percentage = (completed / total) * 100;
    55→  const timeGreeting = getTimeBasedGreeting();
    56→  
    57→  if (completed === total) {
    58→    return `${timeGreeting}! You've smashed every single one today. Proper job, that is. Get some rest, champion.`;
    59→  }
    60→  
    61→  if (completed === 0) {
    62→    return `${timeGreeting}! Nothing done yet? Come on then, let's see what you're made of. Time to get moving!`;
    63→  }
    64→  
    65→  if (percentage >= 75) {
    66→    return `${timeGreeting}! ${completed} out of ${total} done - you're nearly there! Don't go soft on me now.`;
    67→  }
    68→  
    69→  if (percentage >= 50) {
    70→    return `${timeGreeting}! Halfway there with ${completed}/${total}. Keep that energy up, we're building momentum.`;
    71→  }
    72→  
    73→  return `${timeGreeting}! ${completed}/${total} complete. Still got work to do - let's crack on!`;
    74→}
    75→
    76→// ============== INTERFACES ==============
    77→
    78→interface Habit {
    79→  id: string;
    80→  name: string;
    81→  description: string;
    82→  currentStreak: number;
    83→  longestStreak: number;
    84→  totalCheckIns: number;
    85→  createdAt: string;
    86→  lastCheckIn?: string;
    87→  lastCheckInLocal?: string;
    88→}
    89→
    90→interface HabitWithDisplayStreak extends Habit {
    91→  displayStreak: number;
    92→}
    93→
    94→// ============== STREAK LOGIC ==============
    95→
    96→function isCompletedToday(habit: Habit): boolean {
    97→  const today = getLocalDateString();
    98→  if (habit.lastCheckInLocal) return habit.lastCheckInLocal === today;
    99→  if (habit.lastCheckIn) return habit.lastCheckIn.split('T')[0] === today;
   100→  return false;
   101→}
   102→
   103→function isCompletedYesterday(habit: Habit): boolean {
   104→  const yesterday = getYesterdayDateString();
   105→  if (habit.lastCheckInLocal) return habit.lastCheckInLocal === yesterday;
   106→  if (habit.lastCheckIn) return habit.lastCheckIn.split('T')[0] === yesterday;
   107→  return false;
   108→}
   109→
   110→function getDisplayStreak(habit: Habit): number {
   111→  if (isCompletedToday(habit)) return habit.currentStreak;
   112→  if (isCompletedYesterday(habit)) return habit.currentStreak;
   113→  return 0;
   114→}
   115→
   116→// ============== SETTINGS BUTTON COMPONENT ==============
   117→
   118→function SettingsButton({ onPress }: { onPress: () => void }) {
   119→  return (
   120→    <Pressable
   121→      style={({ pressed }) => [
   122→        settingsButtonStyles.container,
   123→        pressed && settingsButtonStyles.pressed,
   124→      ]}
   125→      onPress={onPress}
   126→    >
   127→      <Ionicons name="settings-outline" size={22} color={Colors.textPrimary} />
   128→    </Pressable>
   129→  );
   130→}
   131→
   132→const settingsButtonStyles = StyleSheet.create({
   133→  container: {
   134→    width: 40,
   135→    height: 40,
   136→    borderRadius: 20,
   137→    backgroundColor: 'rgba(0, 0, 0, 0.4)',
   138→    alignItems: 'center',
   139→    justifyContent: 'center',
   140→    borderWidth: 1,
   141→    borderColor: 'rgba(255, 255, 255, 0.1)',
   142→  },
   143→  pressed: {
   144→    backgroundColor: 'rgba(0, 0, 0, 0.6)',
   145→    transform: [{ scale: 0.95 }],
   146→  },
   147→});
   148→
   149→// ============== PROGRESS BAR COMPONENT ==============
   150→
   151→function WarmProgressBar({ completed, total }: { completed: number; total: number }) {
   152→  const percentage = total > 0 ? (completed / total) * 100 : 0;
   153→  
   154→  return (
   155→    <View style={progressStyles.container}>
   156→      <View style={progressStyles.labelRow}>
   157→        <Text style={progressStyles.label}>DAILY PROGRESS</Text>
   158→        <Text style={progressStyles.count}>
   159→          <Text style={progressStyles.countHighlight}>{completed}</Text>/{total}
   160→        </Text>
   161→      </View>
   162→      <View style={progressStyles.barBackground}>
   163→        <View style={[progressStyles.barFill, { width: `${percentage}%` }]} />
   164→        {total > 1 && Array.from({ length: total - 1 }).map((_, i) => (
   165→          <View
   166→            key={i}
   167→            style={[
   168→              progressStyles.segment,
   169→              { left: `${((i + 1) / total) * 100}%` }
   170→            ]}
   171→          />
   172→        ))}
   173→      </View>
   174→    </View>
   175→  );
   176→}
   177→
   178→const progressStyles = StyleSheet.create({
   179→  container: {
   180→    marginBottom: Spacing.lg,
   181→  },
   182→  labelRow: {
   183→    flexDirection: 'row',
   184→    justifyContent: 'space-between',
   185→    alignItems: 'center',
   186→    marginBottom: Spacing.sm,
   187→  },
   188→  label: {
