   197→    color: Colors.textMuted,
   198→  },
   199→  countHighlight: {
   200→    color: Colors.accent,
   201→    fontWeight: '700',
   202→  },
   203→  barBackground: {
   204→    height: 8,
   205→    backgroundColor: Colors.incomplete,
   206→    borderRadius: 4,
   207→    overflow: 'hidden',
   208→    position: 'relative',
   209→  },
   210→  barFill: {
   211→    position: 'absolute',
   212→    left: 0,
   213→    top: 0,
   214→    bottom: 0,
   215→    backgroundColor: Colors.accent,
   216→    borderRadius: 4,
   217→  },
   218→  segment: {
