   250→    top: -12,
   251→    left: Spacing.lg,
   252→    backgroundColor: Colors.nameplateBackground,
   253→    paddingHorizontal: Spacing.md,
   254→    paddingVertical: Spacing.xs + 2,
   255→    borderRadius: BorderRadius.sm,
   256→    zIndex: 10,
   257→  },
   258→  nameplateText: {
   259→    fontSize: 11,
   260→    fontWeight: '700',
   261→    color: Colors.nameplateText,
   262→    letterSpacing: 2,
   263→  },
   264→  dialogueContent: {
   265→    backgroundColor: Colors.dialogueBackground,
   266→    borderWidth: 2,
   267→    borderColor: Colors.dialogueBorder,
   268→    borderRadius: BorderRadius.dialogue,
   269→    paddingTop: Spacing.xl,
   270→    paddingBottom: Spacing.lg,
   271→    paddingHorizontal: Spacing.lg,
   272→    minHeight: 90,
   273→  },
   274→  messageText: {
   275→    fontSize: 16,
   276→    fontWeight: '500',
   277→    color: Colors.textPrimary,
   278→    lineHeight: 24,
   279→  },
   280→});
   281→
   282→// ============== MAIN COMPONENT ==============
   283→
   284→export default function HomeScreen() {
   285→  const [habits, setHabits] = useState<HabitWithDisplayStreak[]>([]);
   286→  const [loading, setLoading] = useState(true);
   287→  const [refreshing, setRefreshing] = useState(false);
   288→  const scrollY = useRef(new Animated.Value(0)).current;
   289→  const router = useRouter();
   290→  const insets = useSafeAreaInsets();
   291→
   292→  const [modal, setModal] = useState({
   293→    visible: false,
   294→    mood: 'talking' as 'pleased' | 'talking',
   295→    title: '',
   296→    message: '',
   297→    buttonText: 'OK',
   298→  });
   299→
   300→  useEffect(() => {
   301→    const userId = auth.currentUser?.uid;
   302→    if (!userId) return;
   303→
   304→    const habitsRef = collection(db, 'users', userId, 'habits');
   305→    const q = query(habitsRef);
   306→
   307→    const unsubscribe = onSnapshot(q, (snapshot) => {
   308→      const habitsData: HabitWithDisplayStreak[] = [];
   309→      snapshot.forEach((docSnap) => {
   310→        const data = docSnap.data();
   311→        const habit = { id: docSnap.id, ...data } as Habit;
   312→        const displayStreak = getDisplayStreak(habit);
   313→        habitsData.push({ ...habit, displayStreak });
   314→      });
   315→      setHabits(habitsData);
   316→      setLoading(false);
   317→      setRefreshing(false);
   318→    });
   319→
   320→    return () => unsubscribe();
   321→  }, []);
   322→
   323→  useEffect(() => {
   324→    const userId = auth.currentUser?.uid;
   325→    if (!userId) return;
   326→
   327→    const checkDailyRoast = async () => {
   328→      try {
   329→        const roastsRef = collection(db, 'users', userId, 'dailyRoasts');
   330→        const q = query(roastsRef, where('read', '==', false), limit(1));
   331→        const snapshot = await getDocs(q);
   332→
   333→        if (!snapshot.empty) {
   334→          const roastDoc = snapshot.docs[0];
   335→          const roastData = roastDoc.data();
   336→          setModal({
   337→            visible: true,
   338→            mood: 'talking',
   339→            title: 'INCOMING MESSAGE',
   340→            message: roastData.message,
   341→            buttonText: 'GOT IT',
   342→          });
   343→          await updateDoc(roastDoc.ref, { read: true });
   344→        }
   345→      } catch (error) {
   346→        console.error('Error checking roast:', error);
   347→      }
   348→    };
   349→
   350→    const timer = setTimeout(checkDailyRoast, 1000);
   351→    return () => clearTimeout(timer);
   352→  }, []);
   353→
   354→  // Pass the ENTIRE habit object so check-in screen has all data immediately
   355→  const handleCheckIn = useCallback((habitId: string) => {
   356→    router.push(`/checkin/${habitId}`);
   357→  }, [router]);
   358→
   359→  const handleDeleteHabit = useCallback(async (habitId: string, habitName: string) => {
   360→    setModal({
   361→      visible: true,
   362→      mood: 'talking',
   363→      title: 'DELETE HABIT',
   364→      message: `Remove "${habitName}"? All progress will be lost.`,
   365→      buttonText: 'CANCEL',
   366→      secondaryButtonText: 'DELETE',
   367→      onSecondaryPress: async () => {
   368→        try {
   369→          const userId = auth.currentUser?.uid;
   370→          if (!userId) return;
   371→          await deleteDoc(doc(db, 'users', userId, 'habits', habitId));
   372→        } catch (error) {
   373→          console.error('Error deleting habit:', error);
   374→        }
   375→      },
   376→    } as any);
   377→  }, []);
   378→
   379→  const handleRefresh = useCallback(() => {
   380→    setRefreshing(true);
   381→  }, []);
   382→
   383→  // Navigate to Settings
   384→  const handleOpenSettings = useCallback(() => {
   385→    router.push('/settings');
   386→  }, [router]);
   387→
   388→  const completedCount = habits.filter(h => isCompletedToday(h)).length;
   389→  const totalCount = habits.length;
   390→
   391→  const characterTranslate = scrollY.interpolate({
   392→    inputRange: [-100, 0, 200],
   393→    outputRange: [-30, 0, 50],
   394→    extrapolate: 'clamp',
   395→  });
   396→
   397→  const characterScale = scrollY.interpolate({
   398→    inputRange: [-100, 0],
   399→    outputRange: [1.15, 1],
   400→    extrapolateRight: 'clamp',
   401→  });
   402→
   403→  // Settings button opacity - fades slightly when scrolling
   404→  const settingsOpacity = scrollY.interpolate({
   405→    inputRange: [0, 100],
   406→    outputRange: [1, 0.7],
   407→    extrapolate: 'clamp',
   408→  });
   409→
   410→  if (loading) {
   411→    return (
   412→      <View style={styles.loadingContainer}>
   413→        <Ionicons name="hourglass-outline" size={32} color={Colors.accent} />
   414→        <Text style={styles.loadingText}>LOADING...</Text>
   415→      </View>
   416→    );
   417→  }
   418→
   419→  return (
   420→    <View style={styles.container}>
   421→      <StatusBar barStyle="light-content" translucent backgroundColor="transparent" />
   422→
   423→      {/* Settings Button - Fixed Position */}
   424→      <Animated.View 
   425→        style={[
   426→          styles.settingsButtonContainer, 
   427→          { 
   428→            top: insets.top + Spacing.sm,
   429→            opacity: settingsOpacity,
   430→          }
   431→        ]}
   432→      >
   433→        <SettingsButton onPress={handleOpenSettings} />
   434→      </Animated.View>
   435→
   436→      {/* Character Section - Image extends behind status bar for full effect */}
   437→      <View style={styles.characterSection}>
   438→        <Animated.Image
   439→          source={require('../../assets/images/apex-home.jpg')}
   440→          style={[
   441→            styles.characterImage,
   442→            {
   443→              transform: [
   444→                { translateY: characterTranslate },
   445→                { scale: characterScale },
   446→              ],
   447→            },
   448→          ]}
   449→          resizeMode="cover"
   450→        />
   451→        
   452→        {/* Gradient only at bottom to fade into content */}
   453→        <LinearGradient
   454→          colors={['transparent', 'rgba(26, 21, 18, 0.5)', Colors.background]}
   455→          locations={[0.5, 0.75, 1]}
   456→          style={styles.characterGradient}
   457→        />
   458→      </View>
   459→
   460→      {/* Scrollable Content */}
   461→      <Animated.ScrollView
   462→        style={styles.scrollView}
   463→        contentContainerStyle={styles.scrollContent}
   464→        showsVerticalScrollIndicator={false}
   465→        scrollEventThrottle={16}
   466→        bounces={false}
   467→        overScrollMode="never"
   468→        refreshControl={
   469→          <RefreshControl
   470→            refreshing={refreshing}
   471→            onRefresh={handleRefresh}
   472→            tintColor={Colors.accent}
   473→            progressViewOffset={CHARACTER_HEIGHT}
   474→          />
   475→        }
   476→        onScroll={Animated.event(
   477→          [{ nativeEvent: { contentOffset: { y: scrollY } } }],
   478→          { useNativeDriver: true }
   479→        )}
   480→      >
   481→        {/* Spacer for character - LARGER to show more of Paddy */}
   482→        <View style={{ height: CHARACTER_HEIGHT - 60 }} />
   483→
   484→        {/* Content with SOLID background */}
   485→        <View style={styles.contentContainer}>
   486→          {/* Dialogue Box */}
   487→          <View style={styles.dialogueWrapper}>
   488→            <DialogueBox
   489→              message={getMotivationalMessage(completedCount, totalCount)}
   490→            />
   491→          </View>
   492→
   493→          {/* Progress Bar */}
   494→          <WarmProgressBar completed={completedCount} total={totalCount} />
   495→
   496→          {/* Habits Section */}
   497→          <View style={styles.sectionHeader}>
   498→            <Ionicons name="list-outline" size={18} color={Colors.textMuted} />
   499→            <Text style={styles.sectionTitle}>TODAY'S HABITS</Text>
   500→            <Text style={styles.sectionCount}>{totalCount}</Text>
   501→          </View>
   502→
   503→          {habits.length === 0 ? (
   504→            <View style={styles.emptyState}>
   505→              <Pressable onPress={() => router.push('/(tabs)/add')}>
   506→                <View style={styles.emptyIcon}>
   507→                  <Ionicons name="add-circle-outline" size={48} color={Colors.textMuted} />
   508→                </View>
   509→              </Pressable>
   510→              <Text style={styles.emptyTitle}>NO HABITS YET</Text>
   511→              <Text style={styles.emptyText}>
   512→                Create your first habit to get started with The Apex Lad.
   513→              </Text>
   514→            </View>
   515→          ) : (
   516→            habits.map((habit) => (
   517→              <SwipeableHabitCard
   518→                key={habit.id}
   519→                habit={habit}
   520→                isCompleted={isCompletedToday(habit)}
   521→                onCheckIn={() => handleCheckIn(habit.id)}
   522→                onDelete={() => handleDeleteHabit(habit.id, habit.name)}
   523→              />
   524→            ))
   525→          )}
   526→
   527→          {/* Bottom Padding */}
   528→          <View style={styles.bottomPadding} />
   529→        </View>
   530→      </Animated.ScrollView>
   531→
   532→      {/* Modal */}
   533→      <ApexModal
   534→        visible={modal.visible}
   535→        mood={modal.mood}
   536→        title={modal.title}
   537→        message={modal.message}
   538→        buttonText={modal.buttonText}
   539→        onClose={() => setModal(prev => ({ ...prev, visible: false }))}
   540→        secondaryButtonText={(modal as any).secondaryButtonText}
   541→        onSecondaryPress={(modal as any).onSecondaryPress}
   542→      />
   543→    </View>
   544→  );
   545→}
   546→
   547→const styles = StyleSheet.create({
   548→  container: {
   549→    flex: 1,
   550→    backgroundColor: Colors.background,
   551→  },
   552→  loadingContainer: {
   553→    flex: 1,
   554→    backgroundColor: Colors.background,
   555→    alignItems: 'center',
   556→    justifyContent: 'center',
   557→  },
   558→  loadingText: {
   559→    color: Colors.textMuted,
   560→    fontSize: 12,
   561→    fontWeight: '600',
   562→    letterSpacing: 2,
   563→    marginTop: Spacing.md,
   564→  },
   565→  // Settings Button - Fixed top right
   566→  settingsButtonContainer: {
   567→    position: 'absolute',
   568→    right: Spacing.md,
   569→    zIndex: 100,
   570→  },
   571→  characterSection: {
