   587→    left: 0,
   588→    right: 0,
   589→    bottom: 0,
   590→    height: CHARACTER_HEIGHT * 0.5,
   591→  },
   592→  scrollView: {
   593→    flex: 1,
   594→    zIndex: 10,
   595→  },
   596→  scrollContent: {
   597→    paddingTop: 0,
   598→  },
   599→  contentContainer: {
   600→    backgroundColor: Colors.background,
   601→    paddingHorizontal: Spacing.lg,
   602→    paddingTop: Spacing.xl,
   603→    minHeight: SCREEN_HEIGHT,
   604→  },
   605→  dialogueWrapper: {
   606→    marginHorizontal: -Spacing.lg,
   607→    paddingHorizontal: Spacing.lg,
   608→    marginBottom: Spacing.lg,
   609→  },
   610→  sectionHeader: {
   611→    flexDirection: 'row',
   612→    alignItems: 'center',
   613→    paddingVertical: Spacing.md,
   614→    marginBottom: Spacing.sm,
   615→  },
   616→  sectionTitle: {
   617→    fontSize: 12,
   618→    fontWeight: '600',
   619→    color: Colors.textMuted,
   620→    letterSpacing: 2,
   621→    marginLeft: Spacing.sm,
   622→    flex: 1,
   623→  },
   624→  sectionCount: {
   625→    fontSize: 14,
   626→    fontWeight: '700',
   627→    color: Colors.textSecondary,
   628→    fontVariant: ['tabular-nums'],
   629→  },
   630→  emptyState: {
   631→    alignItems: 'center',
   632→    justifyContent: 'center',
   633→    paddingVertical: Spacing.xxxl * 2,
   634→    paddingHorizontal: Spacing.xxl,
   635→  },
   636→  emptyIcon: {
   637→    width: 80,
