   186→export default function CheckInScreen() {
   187→  const { id, habitData } = useLocalSearchParams<{ id: string; habitData?: string }>();
   188→  const router = useRouter();
   189→  const functions = getFunctions();
   190→  const insets = useSafeAreaInsets();
   191→
   192→  // Parse habit data from params immediately (no loading needed)
   193→  const initialHabit = React.useMemo(() => {
   194→    if (habitData) {
   195→      try {
   196→        return JSON.parse(habitData) as Habit;
   197→      } catch {
   198→        return null;
   199→      }
   200→    }
   201→    return null;
   202→  }, [habitData]);
   203→
   204→  const [habit, setHabit] = useState<Habit | null>(initialHabit);
   205→  const [imageUri, setImageUri] = useState<string | null>(null);
   206→  const [loading, setLoading] = useState(!initialHabit); // Only load if no data passed
   207→  const [uploading, setUploading] = useState(false);
   208→  const [uploadProgress, setUploadProgress] = useState('');
   209→
   210→  const [modal, setModal] = useState<ModalState>({
   211→    visible: false,
   212→    mood: 'pleased',
   213→    title: '',
   214→    message: '',
   215→    buttonText: 'OK',
   216→    onCloseAction: 'stay',
   217→  });
   218→
   219→  const [success, setSuccess] = useState<SuccessState>({
   220→    visible: false,
   221→    streak: 0,
   222→    habitName: '',
   223→    roastMessage: '',
   224→  });
   225→
   226→  // Only fetch from Firestore if no habit data was passed (fallback)
   227→  useEffect(() => {
   228→    if (!initialHabit) {
   229→      loadHabit();
   230→    }
   231→  }, [id, initialHabit]);
   232→
   233→  const loadHabit = async () => {
   234→    try {
   235→      const userId = auth.currentUser?.uid;
   236→      if (!userId) return;
   237→
   238→      const habitRef = doc(db, 'users', userId, 'habits', id);
   239→      const habitSnap = await getDoc(habitRef);
   240→
   241→      if (habitSnap.exists()) {
   242→        setHabit({ id: habitSnap.id, ...habitSnap.data() } as Habit);
   243→      } else {
   244→        showModal('talking', 'ERROR', 'Habit not found.', 'GO BACK', 'goBack');
   245→      }
   246→    } catch (error) {
   247→      console.error('Error loading habit:', error);
   248→      showModal('talking', 'ERROR', 'Could not load habit data.', 'GO BACK', 'goBack');
   249→    } finally {
   250→      setLoading(false);
   251→    }
   252→  };
   253→
   254→  const showModal = (
   255→    mood: 'pleased' | 'talking',
   256→    title: string,
   257→    message: string,
   258→    buttonText: string = 'OK',
   259→    onCloseAction: 'stay' | 'goBack' = 'stay'
   260→  ) => {
   261→    setModal({ visible: true, mood, title, message, buttonText, onCloseAction });
   262→  };
   263→
   264→  const handleModalClose = () => {
   265→    const action = modal.onCloseAction;
   266→    setModal((prev) => ({ ...prev, visible: false }));
   267→    if (action === 'goBack') router.back();
   268→  };
   269→
   270→  const handleSuccessClose = () => {
   271→    setSuccess((prev) => ({ ...prev, visible: false }));
   272→    router.back();
   273→  };
   274→
   275→  const requestPermissions = async () => {
   276→    const { status: cameraStatus } = await ImagePicker.requestCameraPermissionsAsync();
   277→    const { status: mediaStatus } = await ImagePicker.requestMediaLibraryPermissionsAsync();
   278→
   279→    if (cameraStatus !== 'granted' || mediaStatus !== 'granted') {
   280→      showModal(
   281→        'talking',
   282→        'PERMISSION NEEDED',
   283→        'Camera and photo access required for verification.',
   284→        'GOT IT'
   285→      );
   286→      return false;
   287→    }
   288→    return true;
   289→  };
   290→
   291→  const takePhoto = async () => {
   292→    const hasPermission = await requestPermissions();
   293→    if (!hasPermission) return;
   294→
   295→    const result = await ImagePicker.launchCameraAsync({
   296→      allowsEditing: true,
   297→      aspect: [4, 3],
   298→      quality: 0.7,
   299→    });
   300→
   301→    if (!result.canceled) {
   302→      setImageUri(result.assets[0].uri);
   303→    }
   304→  };
   305→
   306→  const pickImage = async () => {
   307→    const hasPermission = await requestPermissions();
   308→    if (!hasPermission) return;
   309→
   310→    const result = await ImagePicker.launchImageLibraryAsync({
   311→      mediaTypes: ImagePicker.MediaTypeOptions.Images,
   312→      allowsEditing: true,
   313→      aspect: [4, 3],
   314→      quality: 0.7,
   315→    });
   316→
   317→    if (!result.canceled) {
   318→      setImageUri(result.assets[0].uri);
   319→    }
   320→  };
   321→
   322→  const submitCheckIn = async () => {
   323→    if (!imageUri) {
   324→      showModal('talking', 'NO PHOTO', 'Take a photo first to verify your check-in.', 'ALRIGHT');
   325→      return;
   326→    }
   327→
   328→    if (!habit) return;
   329→
   330→    if (isCompletedToday(habit)) {
   331→      showModal(
   332→        'pleased',
   333→        'ALREADY DONE',
   334→        "You've already completed this today! Come back tomorrow.",
   335→        'NICE ONE',
   336→        'goBack'
   337→      );
   338→      return;
   339→    }
   340→
   341→    setUploading(true);
   342→
   343→    try {
   344→      const userId = auth.currentUser?.uid;
   345→      if (!userId) throw new Error('Not authenticated');
   346→
   347→      setUploadProgress('Uploading photo...');
   348→      const photoUrl = await uploadPhoto(imageUri, userId, id);
   349→
   350→      setUploadProgress('Checking your proof...');
   351→      const verifyFunction = httpsCallable(functions, 'verifyHabitPhoto');
   352→      const verifyResult = await verifyFunction({
   353→        photoUrl,
   354→        habitName: habit.name,
   355→        habitDescription: habit.description,
   356→      });
   357→
   358→      const { verified, reason } = verifyResult.data as { verified: boolean; reason: string };
   359→
   360→      if (!verified) {
   361→        setUploading(false);
   362→        setUploadProgress('');
   363→        showModal(
   364→          'talking',
   365→          'NOT QUITE',
   366→          `${reason}\n\nTry again with clearer proof.`,
   367→          'RETRY'
   368→        );
   369→        return;
   370→      }
   371→
   372→      const newStreak = calculateNewStreak(habit);
   373→
   374→      setUploadProgress('Getting your feedback...');
   375→      const roastFunction = httpsCallable(functions, 'generateRoast');
   376→      const roastResult = await roastFunction({
   377→        success: true,
   378→        habitName: habit.name,
   379→        streak: newStreak,
   380→      });
   381→
   382→      const { roast } = roastResult.data as { roast: string };
   383→
   384→      const now = new Date();
   385→      const localDateString = getLocalDateString(now);
   386→
   387→      setUploadProgress('Saving your progress...');
   388→      await addDoc(collection(db, 'users', userId, 'checkins'), {
   389→        habitId: id,
   390→        habitName: habit.name,
   391→        photoUrl,
   392→        timestamp: now.toISOString(),
   393→        localDate: localDateString,
   394→        verified,
   395→        aiReason: reason,
   396→        roast,
   397→      });
   398→
   399→      await updateDoc(doc(db, 'users', userId, 'habits', id), {
   400→        currentStreak: newStreak,
   401→        longestStreak: Math.max(newStreak, habit.longestStreak),
   402→        totalCheckIns: habit.totalCheckIns + 1,
   403→        lastCheckIn: now.toISOString(),
   404→        lastCheckInLocal: localDateString,
   405→      });
   406→
   407→      setUploading(false);
   408→      setUploadProgress('');
   409→
   410→      setSuccess({
   411→        visible: true,
   412→        streak: newStreak,
   413→        habitName: habit.name,
   414→        roastMessage: roast,
   415→      });
   416→    } catch (error: any) {
   417→      console.error('Error submitting check-in:', error);
   418→      setUploading(false);
   419→      setUploadProgress('');
   420→      showModal('talking', 'ERROR', error.message || 'Something went wrong. Try again.', 'RETRY');
   421→    }
   422→  };
   423→
   424→  const uploadPhoto = async (uri: string, userId: string, habitId: string): Promise<string> => {
   425→    const timestamp = Date.now();
   426→    const filename = `${userId}/${habitId}/${timestamp}.jpg`;
   427→
   428→    const response = await fetch(uri);
   429→    const blob = await response.blob();
   430→
   431→    const storageRef = ref(storage, `checkins/${filename}`);
   432→    await uploadBytes(storageRef, blob);
   433→
   434→    return await getDownloadURL(storageRef);
   435→  };
   436→
   437→  // Loading state - with header hidden
   438→  if (loading) {
   439→    return (
   440→      <>
   441→        <Stack.Screen options={{ headerShown: false }} />
   442→        <View style={styles.loadingContainer}>
   443→          <StatusBar barStyle="light-content" />
   444→          <Ionicons name="hourglass-outline" size={32} color={Colors.accent} />
   445→          <Text style={styles.loadingText}>LOADING...</Text>
   446→        </View>
   447→      </>
   448→    );
   449→  }
   450→
   451→  // Error state - with header hidden
   452→  if (!habit) {
   453→    return (
   454→      <>
   455→        <Stack.Screen options={{ headerShown: false }} />
   456→        <View style={styles.loadingContainer}>
   457→          <StatusBar barStyle="light-content" />
   458→          <Ionicons name="alert-circle-outline" size={32} color={Colors.danger} />
   459→          <Text style={styles.loadingText}>HABIT NOT FOUND</Text>
   460→        </View>
   461→      </>
   462→    );
   463→  }
   464→
   465→  const alreadyDoneToday = isCompletedToday(habit);
   466→
   467→  return (
   468→    <>
   469→      {/* Hide the default header */}
   470→      <Stack.Screen options={{ headerShown: false }} />
   471→      
   472→      <View style={styles.container}>
   473→        <StatusBar barStyle="light-content" />
   474→
   475→        {/* Custom Header */}
   476→        <View style={[styles.header, { paddingTop: insets.top + Spacing.sm }]}>
   477→          <Pressable style={styles.backButton} onPress={() => router.back()}>
   478→            <Ionicons name="chevron-back" size={24} color={Colors.textPrimary} />
   479→          </Pressable>
   480→          
   481→          <View style={styles.headerTitleContainer}>
   482→            <Text style={styles.headerLabel}>CHECK-IN</Text>
   483→            <Text style={styles.headerTitle} numberOfLines={1}>
   484→              {habit.name}
   485→            </Text>
   486→          </View>
   487→          
   488→          <View style={styles.streakBadge}>
   489→            <Ionicons name="flame" size={16} color={Colors.streak} />
   490→            <Text style={styles.streakText}>{habit.currentStreak}</Text>
   491→          </View>
   492→        </View>
   493→
   494→        <ScrollView style={styles.content} showsVerticalScrollIndicator={false}>
   495→          {/* Criteria Card */}
   496→          <View style={styles.criteriaCard}>
   497→            <View style={styles.criteriaHeader}>
   498→              <Ionicons name="document-text-outline" size={18} color={Colors.textMuted} />
   499→              <Text style={styles.criteriaLabel}>VERIFICATION CRITERIA</Text>
   500→            </View>
   501→            <Text style={styles.criteriaText}>{habit.description}</Text>
   502→          </View>
   503→
   504→          {alreadyDoneToday ? (
   505→            <View style={styles.completedState}>
   506→              <View style={styles.completedIcon}>
   507→                <Ionicons name="checkmark-circle" size={64} color={Colors.success} />
   508→              </View>
   509→              <Text style={styles.completedTitle}>DONE FOR TODAY</Text>
   510→              <Text style={styles.completedText}>
   511→                You've already completed this habit today. Come back tomorrow!
   512→              </Text>
   513→              <WarmButton
   514→                title="BACK TO HOME"
   515→                onPress={() => router.back()}
   516→                variant="secondary"
   517→              />
   518→            </View>
   519→          ) : (
   520→            <>
   521→              {/* Image Section */}
   522→              {imageUri ? (
   523→                <View style={styles.imageSection}>
   524→                  <Image source={{ uri: imageUri }} style={styles.previewImage} />
   525→                  <Pressable style={styles.retakeButton} onPress={() => setImageUri(null)}>
   526→                    <Ionicons name="refresh-outline" size={18} color={Colors.textSecondary} />
   527→                    <Text style={styles.retakeText}>RETAKE</Text>
   528→                  </Pressable>
   529→                </View>
   530→              ) : (
   531→                <View style={styles.captureSection}>
   532→                  <Pressable style={styles.captureButton} onPress={takePhoto}>
   533→                    <View style={styles.captureIconContainer}>
   534→                      <Ionicons name="camera-outline" size={32} color={Colors.accent} />
   535→                    </View>
   536→                    <Text style={styles.captureTitle}>TAKE A PHOTO</Text>
   537→                    <Text style={styles.captureSubtitle}>Snap your proof</Text>
   538→                  </Pressable>
   539→
   540→                  <Pressable style={styles.galleryButton} onPress={pickImage}>
   541→                    <Ionicons name="images-outline" size={20} color={Colors.textSecondary} />
   542→                    <Text style={styles.galleryText}>CHOOSE FROM GALLERY</Text>
   543→                  </Pressable>
   544→                </View>
   545→              )}
   546→
   547→              {/* Submit Button */}
   548→              {imageUri && (
   549→                <View style={styles.submitSection}>
   550→                  {uploading ? (
   551→                    <View style={styles.uploadingState}>
   552→                      <ActivityIndicator color={Colors.accent} size="small" />
   553→                      <Text style={styles.uploadingText}>{uploadProgress}</Text>
   554→                    </View>
   555→                  ) : (
   556→                    <WarmButton
   557→                      title="SUBMIT CHECK-IN"
   558→                      onPress={submitCheckIn}
   559→                      icon="shield-checkmark-outline"
   560→                    />
   561→                  )}
   562→                </View>
   563→              )}
   564→            </>
   565→          )}
   566→
   567→          <View style={styles.bottomPadding} />
   568→        </ScrollView>
   569→
   570→        <ApexModal
   571→          visible={modal.visible}
   572→          mood={modal.mood}
   573→          title={modal.title}
   574→          message={modal.message}
   575→          buttonText={modal.buttonText}
   576→          onClose={handleModalClose}
   577→        />
   578→
   579→        <ApexSuccessScreen
