    44→function getRandomMessage(messages: string[]): string {
    45→  return messages[Math.floor(Math.random() * messages.length)];
    46→}
    47→
    48→function fillTemplate(template: string, vars: Record<string, string | number>): string {
    49→  let result = template;
    50→  for (const [key, value] of Object.entries(vars)) {
    51→    result = result.replace(new RegExp(`{${key}}`, 'g'), String(value));
    52→  }
    53→  return result;
    54→}
