    56→// ============== TIMEZONE UTILITIES ==============
    57→
    58→function getDateInTimezone(timezone: string): string {
    59→  try {
    60→    const now = new Date();
    61→    const formatted = now.toLocaleDateString('en-CA', {timeZone: timezone});
    62→    return formatted; // Returns YYYY-MM-DD format
    63→  } catch {
    64→    // Fallback to UTC if timezone is invalid
    65→    return new Date().toISOString().split('T')[0];
    66→  }
    67→}
    68→
    69→function getYesterdayInTimezone(timezone: string): string {
    70→  try {
    71→    const now = new Date();
    72→    // Subtract 24 hours
    73→    const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);
    74→    return yesterday.toLocaleDateString('en-CA', {timeZone: timezone});
    75→  } catch {
    76→    const yesterday = new Date();
    77→    yesterday.setDate(yesterday.getDate() - 1);
    78→    return yesterday.toISOString().split('T')[0];
    79→  }
    80→}
    81→
    82→function getCurrentHourInTimezone(timezone: string): number {
    83→  try {
    84→    const now = new Date();
    85→    const hour = parseInt(
    86→      now.toLocaleString('en-US', {timeZone: timezone, hour: 'numeric', hour12: false})
    87→    );
    88→    return hour;
    89→  } catch {
    90→    return new Date().getUTCHours();
    91→  }
    92→}
