    95→// ============== SEND EXPO PUSH NOTIFICATION ==============
    96→
    97→async function sendExpoPushNotification(
    98→  pushToken: string,
    99→  title: string,
   100→  body: string,
   101→  userId?: string
   102→): Promise<boolean> {
   103→  const message = {
   104→    to: pushToken,
   105→    sound: 'default',
   106→    title,
   107→    body,
   108→    data: {type: 'habit_reminder'},
   109→  };
   110→
   111→  try {
   112→    const response = await fetch('https://exp.host/--/api/v2/push/send', {
   113→      method: 'POST',
   114→      headers: {
   115→        'Accept': 'application/json',
   116→        'Accept-encoding': 'gzip, deflate',
   117→        'Content-Type': 'application/json',
   118→      },
   119→      body: JSON.stringify(message),
   120→    });
   121→
   122→    const result = await response.json();
   123→
   124→    if (result.data?.status === 'error') {
   125→      console.error('Expo push error:', result.data.message);
   126→
   127→      // Handle invalid/stale tokens
   128→      const errorMessage = result.data.message || '';
   129→      if (
   130→        errorMessage.includes('DeviceNotRegistered') ||
   131→        errorMessage.includes('InvalidCredentials') ||
   132→        errorMessage.includes('ExpoPushToken') ||
   133→        result.data.details?.error === 'DeviceNotRegistered'
   134→      ) {
   135→        if (userId) {
   136→          console.log(`Removing stale push token for user ${userId}`);
   137→          await admin.firestore().collection('users').doc(userId).update({
   138→            expoPushToken: admin.firestore.FieldValue.delete(),
   139→            pushTokenStaleAt: admin.firestore.FieldValue.serverTimestamp(),
   140→          });
   141→        }
   142→      }
   143→      return false;
   144→    }
   145→
   146→    return true;
   147→  } catch (error) {
   148→    console.error('Error sending push notification:', error);
   149→    return false;
   150→  }
   151→}
