   198→// ============== RATE LIMITING ==============
   199→
   200→async function checkRateLimit(
   201→  userId: string,
   202→  limitType: string,
   203→  maxCalls: number
   204→): Promise<void> {
   205→  const today = new Date().toISOString().split('T')[0];
   206→  const rateLimitRef = admin
   207→    .firestore()
   208→    .collection('rateLimits')
   209→    .doc(`${userId}_${limitType}_${today}`);
   210→
   211→  const rateLimitDoc = await rateLimitRef.get();
   212→  const count = rateLimitDoc.data()?.count || 0;
   213→
   214→  if (count >= maxCalls) {
   215→    throw new HttpsError(
   216→      'resource-exhausted',
   217→      `Daily ${limitType} limit reached (${maxCalls} per day). Try again tomorrow.`
   218→    );
   219→  }
   220→
   221→  await rateLimitRef.set(
   222→    {
   223→      count: count + 1,
   224→      lastCall: admin.firestore.FieldValue.serverTimestamp(),
   225→    },
   226→    {merge: true}
   227→  );
   228→}
